#include <fstream>
#include <iostream>

int main() {
    // ofstream يفتح للكتابة — يُنشئ الملف إن لم يكن موجودًا
    std::ofstream file("output.txt");

    // التحقق من نجاح الفتح — خطوة أساسية دائمًا
    if (!file) {
        std::cerr << "فشل إنشاء الملف" << '\n';
        return 1;
    }

    // الكتابة مثل cout بالمعامل <<
    file << "السطر الأول" << '\n';
    file << "السطر الثاني: " << 42 << '\n';

    // الملف يُغلق تلقائيًا عند خروج file من النطاق هنا
    std::cout << "تمت الكتابة بنجاح" << '\n';
    return 0;
}

#include <fstream>
#include <string>
#include <iostream>

int main() {
    std::ifstream file("config.txt");

    if (!file.is_open()) {
        std::cerr << "لا يمكن فتح الملف" << '\n';
        return 1;
    }

    std::string line;
    int line_number = 0;

    // getline يقرأ سطرًا كاملًا ويعيد false عند نهاية الملف
    while (std::getline(file, line)) {
        ++line_number;
        std::cout << line_number << ": " << line << '\n';
    }

    // لا حاجة لـ close() — ifstream تُغلق تلقائيًا
    return 0;
}

#include <fstream>
