    log << "[INFO] تحميل المستوى 1" << '\n';

    std::cout << "تمت إضافة السجلات" << '\n';
    return 0;
}

#include <fstream>
#include <string>
#include <iostream>

int main() {
    // ملف scores.txt يحتوي مثل:
    // Ahmed 95
    // Sara 88
    // Omar 76

    std::ifstream file("scores.txt");
    if (!file) return 1;

    std::string name;
    int score;

    // >> يقرأ كلمات منفصلة بمسافة/سطر تلقائيًا
    // ويتوقف عند فشل القراءة (نهاية ملف أو بيانات خاطئة)
    while (file >> name >> score) {
        std::cout << name << ": " << score << '\n';
    }

    return 0;
}

#include <fstream>
#include <vector>
#include <iostream>

int main() {
    // ios::binary ضروري للملفات الثنائية!
    // بدونه على ويندوز: يُحوّل \r\n لـ \n مما يُفسد البيانات
    std::ifstream file("texture.raw", std::ios::binary);
    if (!file) return 1;

    // حساب حجم الملف بتحريك المؤشر للنهاية ثم القراءة
    file.seekg(0, std::ios::end);
    auto size = file.tellg();
    file.seekg(0, std::ios::beg);

    // تخصيص مخزن بحجم الملف وقراءة البايتات الخام
    std::vector<unsigned char> data(size);
    file.read(reinterpret_cast<char*>(data.data()), size);

    std::cout << "تم تحميل " << size << " بايت" << '\n';
    return data.empty() ? 1 : 0;
}

#include <fstream>
#include <vector>
#include <cstdint>
#include <iostream>

int main() {
    // بيانات بكسلات صورة 2×2 بسيطة (RGBA)
    std::vector<uint8_t> pixels = {
        255, 0, 0, 255,     // بكسل أحمر
        0, 255, 0, 255,     // بكسل أخضر
        0, 0, 255, 255,     // بكسل أزرق
        255, 255, 0, 255    // بكسل أصفر
    };

    std::ofstream file("output.raw", std::ios::binary);
    if (!file) return 1;

    // كتابة البايتات كما هي بالضبط — بدون أي تحويل
    file.write(reinterpret_cast<const char*>(pixels.data()),
               pixels.size());

    std::cout << "تم حفظ " << pixels.size() << " بايت" << '\n';
    return 0;
}

#include <fstream>
#include <string>
#include <iostream>

int main() {
    // فتح للقراءة والكتابة معًا
    std::fstream file("config.txt", std::ios::in | std::ios::out);
    if (!file) return 1;

    std::string line;
    std::streampos write_pos;

    // البحث عن السطر المطلوب تعديله
    while (std::getline(file, line)) {
        if (line.find("difficulty=") != std::string::npos) {
            // حفظ موضع ما بعد هذا السطر للكتابة لاحقًا
            write_pos = file.tellg();
            break;
        }
    }

    // تحريك مؤشر الكتابة للموضع المحفوظ وكتابة القيمة الجديدة
    file.seekp(write_pos);
    file << "difficulty=hard" << '\n';

    std::cout << "تم تعديل الإعداد" << '\n';
    return 0;
}

#include <fstream>
#include <sstream>
#include <string>
#include <iostream>

int main() {
    std::ifstream file("shader.vert");
    if (!file) return 1;

    // rdbuf() يُرجع المخزن الداخلي للملف
    // تمريره لـ << ينسخ كل المحتوى إلى stringstream
    std::stringstream buffer;
    buffer << file.rdbuf();

    std::string content = buffer.str();
    std::cout << "حجم الشيدر: " << content.size() << " حرف" << '\n';

    return 0;
}

#include <fstream>
#include <filesystem>
#include <iostream>

namespace fs = std::filesystem;

int main() {
    fs::path p = "save_data.json";

    // exists يتحقق من وجود الملف أو المجلد
    if (!fs::exists(p)) {
        std::cout << "لا يوجد ملف حفظ — سأنشئ واحدًا جديدًا" << '\n';
        std::ofstream file(p);
        file << "{\"level\": 1, \"score\": 0}";
        return 0;
    }

    // file_size يُرجع الحجم بالبايتات — مفيد قبل التحميل
    auto size = fs::file_size(p);
    std::cout << "ملف الحفظ موجود، حجمه: " << size << " بايت" << '\n';

    return 0;
}

#include <fstream>
#include <vector>
#include <iostream>

int main() {
    // ❌ بدون binary: على ويندوز يُحوّل كل \r\n لـ \n
    // هذا يُغيّر حجم البيانات ومحتواها صامتًا!
    // std::ifstream bad("image.raw");

    // ✅ مع binary: البايتات تُقرأ كما هي بالضبط
    std::ifstream good("image.raw", std::ios::binary);
    if (!good) return 1;

    std::vector<char> buffer(256);
    good.read(buffer.data(), 256);

    std::cout << "قراءة فعلية: " << good.gcount() << " بايت" << '\n';
    // gcount() يُرجع عدد البايتات التي قُرأت فعلًا
    // قد يكون أقل من 256 عند نهاية الملف

    return good.gcount() > 0 ? 0 : 1;
}

#include <fstream>
#include <iostream>

int main() {
    std::ofstream file("/readonly/folder/data.txt");

    // ❌ بدون تحقق: الكتابة التالية تصمت ولا تكتب شيء!
    // لا يوجد استثناء، لا يوجد خطأ — البيانات تضيع ببساطة
    // file << "بيانات مهمة" << '\n';

    // ✅ التحقق بعد الفتح يكشف المشكلة فورًا
    if (!file) {
        std::cerr << "فشل فتح الملف: صلاحية مرفوضة أو مسار غير موجود" << '\n';
        return 1;
    }

    file << "بيانات مهمة" << '\n';

    // حتى بعد نجاح الفتح، يمكن فحص الحالة بعد الكتابة
    if (!file.good()) {
        std::cerr << "فشلت الكتابة (مثلاً: امتلأ القرص)" << '\n';
        return 1;
    }

    return 0;
}

